import { useState, useEffect, useContext } from "react";
import api, {
  getUserById,
  getReviewsByUser,
  createReview,
  updateUser,
  getProposalsByVehicle, // <-- Adicionado
  getImageUrl, // <-- Adicionado
} from "../servicos/api";
import VehicleCard from "../components/VehicleCard";
import "./ProfilePage.css";
import { useNavigate, useParams, Link } from "react-router-dom"; // <-- Link adicionado
import { AuthContext } from "../contexts/AuthContext";

export default function ProfilePage() {
  const navigate = useNavigate();
  const { id } = useParams(); // ID do perfil que estamos visitando
  const { currentUser } = useContext(AuthContext); // Usuário que está logado

  // 1. Define quem é o dono deste perfil (Prioridade para o ID da URL)
  const targetId = id || currentUser?.id;

  // 2. Checagem única se o perfil é meu (usando String para evitar erro de tipo)
  const isSelf = currentUser && String(currentUser.id) === String(targetId);

  const [user, setUser] = useState(null);
  const [reviews, setReviews] = useState([]);
  const [vehicles, setVehicles] = useState([]);
  const [pendingProposals, setPendingProposals] = useState([]); // <-- Novo State para propostas
  const [showReviewModal, setShowReviewModal] = useState(false);
  const [reviewForm, setReviewForm] = useState({ rating: 5, comment: "" });
  const [targetReviewUser, setTargetReviewUser] = useState(null);
  const [soldVehicles, setSoldVehicles] = useState([]);
  const [tab, setTab] = useState("vehicles");
  const [loading, setLoading] = useState(true);
  const [editing, setEditing] = useState(false);
  const [editForm, setEditForm] = useState({ name: "", phone: "", email: "" });

  // States de Avaliação...
  const [revForm, setRevForm] = useState({ rating: 5, comment: "" });
  const [revError, setRevError] = useState("");
  const [revSuccess, setRevSuccess] = useState("");

  useEffect(() => {
    if (!targetId) {
      navigate("/login");
      return;
    }

    setLoading(true);

    Promise.all([
      getUserById(targetId),
      getReviewsByUser(targetId),
      api.get("/vehicles?includeSold=true").then((res) => res.data),
    ])
      .then(async ([u, r, v]) => {
        setUser(u);
        setReviews(Array.isArray(r) ? r : []);

        // 3. FILTRAGEM MELHORADA
        const allVehicles =
          v && Array.isArray(v.vehicles)
            ? v.vehicles
            : Array.isArray(v)
              ? v
              : [];

        // Pega todos os veículos do usuário primeiro
        const userVehicles = allVehicles.filter(
          (veh) => String(veh.userId) === String(targetId),
        );

        // Separa em Ativos (Anúncios) e Vendidos
        const active = userVehicles.filter((veh) => veh.status !== "sold");
        const sold = userVehicles.filter((veh) => veh.status === "sold");

        setVehicles(active); // Alimenta a aba "Anúncios"
        setSoldVehicles(sold); // Alimenta a nova aba "Vendidos"

        // 4. BUSCA DE PROPOSTAS PENDENTES (Mantemos a lógica sobre os ativos)
        if (isSelf) {
          try {
            const proposalsPromises = active.map((veh) =>
              getProposalsByVehicle(veh.id)
                .then((res) => {
                  const props = Array.isArray(res) ? res : [];
                  return props.map((p) => ({ ...p, targetVehicle: veh }));
                })
                .catch(() => []),
            );

            const allProposalsArrays = await Promise.all(proposalsPromises);
            const allProposals = allProposalsArrays.flat();

            const pending = allProposals.filter((p) => p.status === "PENDING");
            setPendingProposals(pending);
          } catch (error) {
            console.error("Erro ao buscar propostas pendentes:", error);
          }
        }

        setEditForm({
          name: u.name || "",
          phone: u.phone || "",
          email: u.email || "",
        });
        setLoading(false);
      })
      .catch((err) => {
        console.error("Erro ao carregar dados:", err);
        navigate("/");
      });
  }, [targetId, navigate, isSelf]);

  const handleSubmitReview = async (e) => {
    e.preventDefault();
    try {
      await api.post("/reviews", {
        reviewedId: targetReviewUser.id,
        rating: reviewForm.rating,
        comment: reviewForm.comment,
      });
      alert("Avaliação enviada com sucesso!");
      setShowReviewModal(false);
      setReviewForm({ rating: 5, comment: "" });

      // Opcional: Atualiza a lista de reviews se estiver avaliando a si mesmo (raro, mas evita F5)
      // window.location.reload();
    } catch (error) {
      alert(error.response?.data?.error || "Erro ao enviar avaliação.");
    }
  };

  const avg = reviews.length
    ? (reviews.reduce((a, r) => a + r.rating, 0) / reviews.length).toFixed(1)
    : null;

  const handleReview = async (e) => {
    e.preventDefault();
    setRevError("");
    setRevSuccess("");

    const res = await createReview({
      reviewerId: currentUser.id,
      reviewedId: targetId,
      rating: Number(revForm.rating),
      comment: revForm.comment,
    });

    if (res.error) {
      setRevError(res.error);
      return;
    }

    setRevSuccess("Avaliação enviada!");
    setReviews((prev) => [
      ...prev,
      { ...res.review, reviewer: { name: currentUser.name } },
    ]);
  };

  const handleSave = async () => {
    await updateUser(targetId, editForm);
    setUser({ ...user, ...editForm });
    setEditing(false);
  };

  if (loading) {
    return (
      <div className="profile-page">
        <div className="profile-center">Carregando...</div>
      </div>
    );
  }

  return (
    <div className="profile-page">
      <div className="profile-layout">
        <aside className="profile-sidebar">
          <div className="avatar-lg">{user?.name?.[0]?.toUpperCase()}</div>

          {editing ? (
            <div className="edit-form">
              <input
                className="profile-input"
                value={editForm.name}
                onChange={(e) =>
                  setEditForm({ ...editForm, name: e.target.value })
                }
                placeholder="Nome"
              />
              <input
                className="profile-input"
                value={editForm.phone}
                onChange={(e) =>
                  setEditForm({ ...editForm, phone: e.target.value })
                }
                placeholder="Telefone"
              />
              <input
                className="profile-input"
                value={editForm.email}
                onChange={(e) =>
                  setEditForm({ ...editForm, email: e.target.value })
                }
                placeholder="E-mail"
              />
              <button className="btn" onClick={handleSave}>
                Salvar
              </button>
              <button className="btn-outline" onClick={() => setEditing(false)}>
                Cancelar
              </button>
            </div>
          ) : (
            <>
              <h2 className="profile-name">{user?.name}</h2>
              <p className="profile-sub">{user?.email}</p>
              <p className="profile-sub">{user?.phone}</p>

              {avg && (
                <div className="profile-rating-box">
                  <div className="profile-stars">
                    {"★".repeat(Math.round(avg))}
                    {"☆".repeat(5 - Math.round(avg))}
                  </div>
                  <p className="profile-rating-text">
                    {avg} ({reviews.length} avaliações)
                  </p>
                </div>
              )}

              {isSelf && (
                <button
                  className="btn-outline"
                  onClick={() => setEditing(true)}
                >
                  ✏️ Editar Perfil
                </button>
              )}
            </>
          )}
        </aside>

        <div>
          <div className="profile-tabs">
            <button
              className={`profile-tab ${tab === "vehicles" ? "profile-tab-active" : ""}`}
              onClick={() => setTab("vehicles")}
            >
              Anúncios ({vehicles.length})
            </button>

            {/* ABA DE PROPOSTAS - SÓ APARECE PARA O DONO */}
            {isSelf && (
              <button
                className={`profile-tab ${tab === "proposals" ? "profile-tab-active" : ""}`}
                onClick={() => setTab("proposals")}
              >
                Novas Propostas ({pendingProposals.length})
              </button>
            )}

            {isSelf && (
              <button
                className={`profile-tab ${tab === "sold" ? "profile-tab-active" : ""}`}
                onClick={() => setTab("sold")}
              >
                Vendidos ({soldVehicles.length})
              </button>
            )}

            <button
              className={`profile-tab ${tab === "reviews" ? "profile-tab-active" : ""}`}
              onClick={() => setTab("reviews")}
            >
              Avaliações ({reviews.length})
            </button>
          </div>

          {tab === "vehicles" &&
            (vehicles.length === 0 ? (
              <div className="profile-empty">
                🚗 Nenhum anúncio ainda.
                {isSelf && (
                  <button
                    className="btn profile-empty-btn"
                    onClick={() => navigate("/anunciar")}
                  >
                    Anunciar agora
                  </button>
                )}
              </div>
            ) : (
              <div className="profile-grid">
                {vehicles.map((v) => (
                  <VehicleCard
                    key={v.id}
                    vehicle={v}
                    onClick={() => navigate(`/veiculo/${v.id}`)}
                  />
                ))}
              </div>
            ))}

          {/* CONTEÚDO DA NOVA ABA DE PROPOSTAS */}
          {tab === "proposals" && isSelf && (
            <div>
              {pendingProposals.length === 0 ? (
                <div className="profile-empty">
                  Nenhuma proposta pendente no momento.
                </div>
              ) : (
                pendingProposals.map((p) => (
                  <div key={p.id} className="perfil-proposal-card">
                    <div className="perfil-prop-action">
                      <Link
                        to={`/proposta/${p.id}`}
                        className="perfil-btn-circle"
                      >
                        Ver
                        <br />
                        Proposta
                      </Link>
                    </div>

                    <div className="perfil-prop-info">
                      <h3>
                        Veículo: {p.targetVehicle?.brand}{" "}
                        {p.targetVehicle?.model}
                      </h3>
                      <p>
                        <strong>Valor Ofertado:</strong>{" "}
                        {Number(p.cashOffer).toLocaleString("pt-BR", {
                          style: "currency",
                          currency: "BRL",
                        })}
                        {p.offeredVehicleId ? " + 1 veículo" : ""}
                      </p>
                      <p>
                        <strong>Mensagem:</strong> {p.message || "Sem mensagem"}
                      </p>
                      <p className="perfil-prop-owner">
                        Dono da Oferta:{" "}
                        {p.buyer?.name?.split(" ")[0] || "Comprador"}
                      </p>
                    </div>

                    <div className="perfil-prop-image-box">
                      <img
                        src={
                          p.targetVehicle?.images?.[0]?.url
                            ? getImageUrl(p.targetVehicle.images[0].url)
                            : "/fallback-autozoom.png"
                        }
                        alt="Veículo"
                        className="perfil-prop-image"
                        onError={(e) => {
                          e.target.onerror = null;
                          e.target.src = "/fallback-autozoom.png";
                        }}
                      />
                    </div>
                  </div>
                ))
              )}
            </div>
          )}

          {tab === "sold" && isSelf && (
            <div>
              {soldVehicles.length === 0 ? (
                <div className="profile-empty">
                  Você ainda não concluiu nenhuma venda.
                </div>
              ) : (
                soldVehicles.map((v) => (
                  <div
                    key={v.id}
                    className="perfil-proposal-card perfil-sold-card"
                  >
                    {/* Lado Esquerdo: Info da Venda */}
                    <div className="perfil-prop-info">
                      <div
                        style={{
                          display: "flex",
                          justifyContent: "space-between",
                          alignItems: "flex-start",
                        }}
                      >
                        <h3>
                          {v.brand} {v.model}
                        </h3>
                        <span className="sold-badge">VENDIDO</span>
                      </div>

                      <p>
                        <strong>Motor:</strong> {v.engine}
                      </p>
                      <p>
                        <strong>Data da Venda:</strong>{" "}
                        {new Date(v.updatedAt).toLocaleDateString("pt-BR")}
                      </p>

                      {/* Aqui usamos o p.Buyer?.name que deve vir do include do seu Back-end */}
                      <p className="perfil-prop-owner">
                        Comprador:{" "}
                        {v.Buyer?.name || "Vendido em outra plataforma"}
                      </p>
                    </div>

                    {/* Lado Direito: Foto Principal */}
                    <div className="perfil-prop-image-box">
                      <img
                        src={
                          v.images?.[0]?.url
                            ? getImageUrl(v.images[0].url)
                            : "/fallback-autozoom.png"
                        }
                        alt="Veículo Vendido"
                        className="perfil-prop-image"
                        onError={(e) => {
                          e.target.onerror = null;
                          e.target.src = "/fallback-autozoom.png";
                        }}
                      />

                      {currentUser && (
                        <>
                          {/* Se eu sou o VENDEDOR do carro, avalio o Comprador */}
                          {isSelf && v.Buyer && (
                            <button
                              className="btn-avaliar"
                              onClick={() => {
                                setTargetReviewUser({
                                  id: v.buyerId,
                                  name: v.Buyer.name,
                                });
                                setShowReviewModal(true);
                              }}
                            >
                              Avaliar Comprador
                            </button>
                          )}

                          {/* Se eu sou o COMPRADOR, avalio o Vendedor */}
                          {!isSelf && v.buyerId === currentUser.id && (
                            <button
                              className="btn-avaliar"
                              onClick={() => {
                                setTargetReviewUser({
                                  id: v.userId,
                                  name: user.name,
                                });
                                setShowReviewModal(true);
                              }}
                            >
                              Avaliar Vendedor
                            </button>
                          )}
                        </>
                      )}
                    </div>
                  </div>
                ))
              )}
            </div>
          )}

          {tab === "reviews" && (
            <div>
              {reviews.length === 0 ? (
                <div className="profile-empty">
                  ⭐ Nenhuma avaliação recebida ainda.
                </div>
              ) : (
                <div className="perfil-reviews-grid">
                  {reviews.map((rev) => (
                    <div key={rev.id} className="perfil-review-card">
                      <div className="review-header">
                        {/* Mostra as estrelinhas dinamicamente */}
                        <span className="stars">
                          {"⭐".repeat(rev.rating)}
                          {"☆".repeat(5 - rev.rating)}
                        </span>
                        <span className="review-date">
                          {new Date(rev.createdAt).toLocaleDateString("pt-BR")}
                        </span>
                      </div>

                      <p className="review-comment">"{rev.comment}"</p>

                      <div className="review-author">
                        <span>
                          Avaliado por:{" "}
                          <strong>{rev.Reviewer?.name || "Usuário"}</strong>
                        </span>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
